"use client"

import {
  useMnemonicFlow,
  type UseMnemonicFlowOptions,
} from "./use-mnemonic-flow"
import { MnemonicFlowUi } from "./mnemonic-flow-ui"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export {
  useMnemonicFlow,
  type UseMnemonicFlowOptions,
  type UseMnemonicFlowReturn,
  type MnemonicFlowMode,
  type MnemonicWordCount,
  type VerificationChallenge,
} from "./use-mnemonic-flow"

export {
  MnemonicFlowUi,
  type MnemonicFlowUiProps,
} from "./mnemonic-flow-ui"

export {
  MnemonicGridUi,
  type MnemonicGridUiProps,
  type WordSlotProps,
  type WordSlotMode,
} from "./mnemonic-grid-ui"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Props for the composed MnemonicFlow component */
export interface MnemonicFlowProps {
  /** Operating mode: display, create, import, or verify */
  mode: UseMnemonicFlowOptions["mode"]
  /** Pre-populated words for display/verify modes */
  words?: string[]
  /** Number of words (12 or 24, default: 12) */
  wordCount?: UseMnemonicFlowOptions["wordCount"]
  /** Called when the flow completes with the final word list */
  onComplete?: (words: string[]) => void
  /** Called when the user cancels */
  onCancel?: () => void
  /** External loading state (e.g., wallet creation in progress) */
  isLoading?: boolean
  /** External error message */
  error?: string | null
  /** Additional CSS classes */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * Multi-mode seed phrase display and input block.
 *
 * Composes `useMnemonicFlow` (logic) with `MnemonicFlowUi` (presentation)
 * into a single, ready-to-use component.
 *
 * Modes:
 * - **display**: Read-only numbered grid with copy-all button
 * - **create**: Generated words + display + confirmation checkbox
 * - **import**: Editable input grid for entering words
 * - **verify**: Show 2 random positions, user must type the correct words
 *
 * @example
 * ```tsx
 * import { MnemonicFlow } from "@/components/blocks/mnemonic-flow"
 *
 * <MnemonicFlow
 *   mode="create"
 *   words={generatedWords}
 *   onComplete={(words) => createWallet(words.join(" "))}
 *   onCancel={() => router.back()}
 * />
 * ```
 */
export function MnemonicFlow({
  mode,
  words: initialWords,
  wordCount = 12,
  onComplete,
  onCancel,
  isLoading = false,
  error: externalError,
  className,
}: MnemonicFlowProps) {
  const flow = useMnemonicFlow({
    mode,
    words: initialWords,
    wordCount,
    onComplete,
    onCancel,
  })

  return (
    <MnemonicFlowUi
      mode={flow.mode}
      words={flow.words}
      wordCount={flow.wordCount}
      confirmed={flow.confirmed}
      onConfirmedChange={flow.setConfirmed}
      onWordChange={flow.setWord}
      challenge={flow.challenge}
      onVerificationAnswer={flow.setVerificationAnswer}
      isValid={flow.isValid}
      canSubmit={flow.canSubmit}
      onSubmit={flow.submit}
      onCancel={flow.cancel}
      onCopy={flow.copyWords}
      copied={flow.copied}
      isLoading={isLoading}
      error={externalError ?? flow.error}
      className={className}
    />
  )
}

"use client"

import { useMemo } from "react"
import { Check, ClipboardCopy, Loader2, X } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"
import { MnemonicGridUi } from "./mnemonic-grid-ui"
import type {
  MnemonicFlowMode,
  MnemonicWordCount,
  VerificationChallenge,
} from "./use-mnemonic-flow"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Props for the mnemonic flow UI shell */
export interface MnemonicFlowUiProps {
  /** Operating mode */
  mode: MnemonicFlowMode
  /** Word list */
  words: string[]
  /** Expected word count */
  wordCount: MnemonicWordCount
  /** Whether the confirmation checkbox is checked */
  confirmed: boolean
  /** Toggle confirmation */
  onConfirmedChange: (value: boolean) => void
  /** Update a word at index */
  onWordChange: (index: number, value: string) => void
  /** Verification challenge (verify mode only) */
  challenge: VerificationChallenge | null
  /** Update a verification answer */
  onVerificationAnswer: (position: number, value: string) => void
  /** Whether the state is valid */
  isValid: boolean
  /** Whether submit is enabled */
  canSubmit: boolean
  /** Handle submit */
  onSubmit: () => void
  /** Handle cancel */
  onCancel: () => void
  /** Copy all words */
  onCopy: () => void
  /** Whether words were recently copied */
  copied: boolean
  /** External loading state */
  isLoading?: boolean
  /** Error message */
  error?: string | null
  /** Additional CSS classes */
  className?: string
}

// ---------------------------------------------------------------------------
// Mode config
// ---------------------------------------------------------------------------

interface ModeConfig {
  title: string
  description: string
  submitLabel: string
}

function getModeConfig(mode: MnemonicFlowMode, wordCount: MnemonicWordCount): ModeConfig {
  switch (mode) {
    case "display":
      return {
        title: "Recovery Phrase",
        description: `Your ${wordCount}-word recovery phrase. Store it securely.`,
        submitLabel: "Done",
      }
    case "create":
      return {
        title: "Create Recovery Phrase",
        description: `Write down these ${wordCount} words in order. You will need them to recover your wallet.`,
        submitLabel: "Continue",
      }
    case "import":
      return {
        title: "Import Recovery Phrase",
        description: `Enter your ${wordCount}-word recovery phrase to restore your wallet.`,
        submitLabel: "Import Wallet",
      }
    case "verify":
      return {
        title: "Verify Recovery Phrase",
        description:
          "Confirm you saved your recovery phrase by entering the words at the highlighted positions.",
        submitLabel: "Verify",
      }
  }
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * Full mnemonic flow UI with header, grid, confirmation, and action buttons.
 *
 * Pure presentation — all state and callbacks come through props. Pair with
 * `useMnemonicFlow` for the logic layer.
 */
export function MnemonicFlowUi({
  mode,
  words,
  wordCount,
  confirmed,
  onConfirmedChange,
  onWordChange,
  challenge,
  onVerificationAnswer,
  isValid,
  canSubmit,
  onSubmit,
  onCancel,
  onCopy,
  copied,
  isLoading = false,
  error,
  className,
}: MnemonicFlowUiProps) {
  const config = getModeConfig(mode, wordCount)

  // Build position sets for the grid
  const editablePositions = useMemo(() => {
    if (mode === "import") {
      return new Set(Array.from({ length: words.length }, (_, i) => i))
    }
    return undefined
  }, [mode, words.length])

  const blankPositions = useMemo(() => {
    if (mode === "verify" && challenge) {
      return new Set(challenge.positions)
    }
    return undefined
  }, [mode, challenge])

  return (
    <Card className={cn("w-full", className)}>
      <CardHeader>
        <div className="flex items-center justify-between">
          <div className="flex flex-col gap-1.5">
            <CardTitle>{config.title}</CardTitle>
            <CardDescription>{config.description}</CardDescription>
          </div>
          <Badge variant="outline" className="shrink-0">
            {wordCount} words
          </Badge>
        </div>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* Word grid */}
        <MnemonicGridUi
          words={words}
          columns={4}
          editablePositions={editablePositions}
          blankPositions={blankPositions}
          onWordChange={onWordChange}
          blankValues={challenge?.answers}
          onBlankChange={onVerificationAnswer}
        />

        {/* Copy button for display and create modes */}
        {(mode === "display" || mode === "create") && (
          <Button
            variant="outline"
            size="sm"
            className="self-end"
            onClick={onCopy}
            aria-label="Copy recovery phrase"
          >
            {copied ? (
              <>
                <Check data-icon="inline-start" />
                Copied
              </>
            ) : (
              <>
                <ClipboardCopy data-icon="inline-start" />
                Copy All
              </>
            )}
          </Button>
        )}

        {/* Confirmation checkbox for create mode */}
        {mode === "create" && (
          <div className="flex items-center gap-2 rounded-md border border-border bg-muted/50 px-4 py-3">
            <Checkbox
              id="mnemonic-confirm"
              checked={confirmed}
              onCheckedChange={(checked) =>
                onConfirmedChange(checked === true)
              }
            />
            <Label
              htmlFor="mnemonic-confirm"
              className="cursor-pointer select-none text-sm"
            >
              I have written down my recovery phrase
            </Label>
          </div>
        )}

        {/* Verification hint */}
        {mode === "verify" && challenge && (
          <p className="text-sm text-muted-foreground">
            Enter word{" "}
            <span className="font-mono font-medium text-foreground">
              #{challenge.positions[0] + 1}
            </span>{" "}
            and{" "}
            <span className="font-mono font-medium text-foreground">
              #{challenge.positions[1] + 1}
            </span>{" "}
            from your recovery phrase.
          </p>
        )}

        {/* Error message */}
        {error && (
          <div className="flex items-start gap-3 rounded-md border border-destructive/20 bg-destructive/5 p-4">
            <X className="mt-0.5 size-4 shrink-0 text-destructive" />
            <p className="text-sm text-destructive">{error}</p>
          </div>
        )}
      </CardContent>

      {/* Footer with action buttons (hidden in pure display mode) */}
      {mode !== "display" && (
        <CardFooter className="flex gap-3">
          <Button variant="outline" className="flex-1" onClick={onCancel}>
            Cancel
          </Button>
          <Button
            className="flex-1"
            onClick={onSubmit}
            disabled={!canSubmit || isLoading}
            aria-busy={isLoading}
          >
            {isLoading ? (
              <>
                <Loader2 className="animate-spin" data-icon="inline-start" />
                Processing...
              </>
            ) : (
              config.submitLabel
            )}
          </Button>
        </CardFooter>
      )}
    </Card>
  )
}

"use client"

import { useCallback } from "react"
import { Input } from "@/components/ui/input"
import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** A single word slot that can be read-only, editable, or a verification blank */
export type WordSlotMode = "readonly" | "editable" | "blank"

/** Props for an individual word slot in the grid */
export interface WordSlotProps {
  /** 1-based position number */
  position: number
  /** The word to display (empty string for blanks) */
  word: string
  /** How the slot behaves */
  slotMode: WordSlotMode
  /** Called when the user changes a word (editable or blank mode) */
  onChange?: (value: string) => void
  /** Placeholder text for input fields */
  placeholder?: string
}

/** Props for the full mnemonic grid */
export interface MnemonicGridUiProps {
  /** The word list to render */
  words: string[]
  /** How many columns to show (default: 4) */
  columns?: 3 | 4
  /** Set of positions (0-indexed) that should be editable inputs */
  editablePositions?: Set<number>
  /** Set of positions (0-indexed) that are verification blanks */
  blankPositions?: Set<number>
  /** Called when a word changes (index, value) */
  onWordChange?: (index: number, value: string) => void
  /** Values for blank/verification positions keyed by index */
  blankValues?: Record<number, string>
  /** Called when a blank value changes (index, value) */
  onBlankChange?: (index: number, value: string) => void
  /** Additional CSS classes */
  className?: string
}

// ---------------------------------------------------------------------------
// Word Slot
// ---------------------------------------------------------------------------

function WordSlot({
  position,
  word,
  slotMode,
  onChange,
  placeholder,
}: WordSlotProps) {
  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      onChange?.(e.target.value)
    },
    [onChange]
  )

  return (
    <div
      className={cn(
        "flex items-center gap-2 rounded-md border border-border bg-muted/50 px-3 py-2",
        slotMode === "blank" && "border-primary/50 bg-primary/5"
      )}
    >
      <span className="shrink-0 w-6 text-right text-xs font-mono text-muted-foreground">
        {position}.
      </span>
      {slotMode === "readonly" ? (
        <span className="text-sm font-mono text-foreground select-all truncate">
          {word}
        </span>
      ) : (
        <Input
          type="text"
          value={slotMode === "blank" ? undefined : word}
          defaultValue={slotMode === "blank" ? "" : undefined}
          onChange={handleChange}
          className="h-auto border-0 bg-transparent p-0 text-sm font-mono shadow-none focus-visible:ring-0"
          placeholder={placeholder ?? `word ${position}`}
          autoComplete="off"
          spellCheck={false}
          autoCapitalize="none"
          aria-label={`Word ${position}`}
        />
      )}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Mnemonic Grid
// ---------------------------------------------------------------------------

/**
 * A numbered grid of mnemonic seed words.
 *
 * Supports three slot modes:
 * - **readonly**: Displays the word as text (display/create modes)
 * - **editable**: Renders an input for the user to type a word (import mode)
 * - **blank**: Shows an empty input the user must fill in (verify mode)
 *
 * Pure presentation component — receives all data and callbacks via props.
 */
export function MnemonicGridUi({
  words,
  columns = 4,
  editablePositions,
  blankPositions,
  onWordChange,
  blankValues,
  onBlankChange,
  className,
}: MnemonicGridUiProps) {
  const gridCols =
    columns === 3
      ? "grid-cols-3"
      : "grid-cols-2 sm:grid-cols-4"

  return (
    <div className={cn("grid gap-2", gridCols, className)}>
      {words.map((word, index) => {
        const isBlank = blankPositions?.has(index) ?? false
        const isEditable = editablePositions?.has(index) ?? false

        let slotMode: WordSlotMode = "readonly"
        if (isBlank) slotMode = "blank"
        else if (isEditable) slotMode = "editable"

        const displayWord = isBlank
          ? (blankValues?.[index] ?? "")
          : word

        const handleSlotChange = isBlank
          ? (value: string) => onBlankChange?.(index, value)
          : isEditable
            ? (value: string) => onWordChange?.(index, value)
            : undefined

        return (
          <WordSlot
            // Position is the stable identity for mnemonic grids
            key={index}
            position={index + 1}
            word={displayWord}
            slotMode={slotMode}
            onChange={handleSlotChange}
            placeholder={
              isBlank
                ? `word ${index + 1}`
                : isEditable
                  ? `word ${index + 1}`
                  : undefined
            }
          />
        )
      })}
    </div>
  )
}

import { useCallback, useMemo, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Supported operating modes for the mnemonic flow */
export type MnemonicFlowMode = "display" | "create" | "import" | "verify"

/** Number of words in a mnemonic seed phrase */
export type MnemonicWordCount = 12 | 24

/** A verification challenge requiring the user to confirm specific word positions */
export interface VerificationChallenge {
  /** The two positions (0-indexed) the user must fill in */
  positions: [number, number]
  /** The user's current answers keyed by position index */
  answers: Record<number, string>
}

/** Options for the useMnemonicFlow hook */
export interface UseMnemonicFlowOptions {
  /** Operating mode (default: "display") */
  mode: MnemonicFlowMode
  /** Pre-populated words for display/verify modes */
  words?: string[]
  /** Number of words to generate/import (default: 12) */
  wordCount?: MnemonicWordCount
  /** Called when the flow completes with the final word list */
  onComplete?: (words: string[]) => void
  /** Called when the user cancels the flow */
  onCancel?: () => void
}

/** Return value of the useMnemonicFlow hook */
export interface UseMnemonicFlowReturn {
  /** The current word list */
  words: string[]
  /** The operating mode */
  mode: MnemonicFlowMode
  /** Expected word count */
  wordCount: MnemonicWordCount
  /** Whether the confirmation checkbox is checked (create mode) */
  confirmed: boolean
  /** Toggle the confirmation checkbox */
  setConfirmed: (value: boolean) => void
  /** Update a single word at a given index (import mode) */
  setWord: (index: number, value: string) => void
  /** Replace the full word list */
  setWords: (words: string[]) => void
  /** Verification challenge state (verify mode) */
  challenge: VerificationChallenge | null
  /** Update a verification answer */
  setVerificationAnswer: (position: number, value: string) => void
  /** Whether the current state is valid for submission */
  isValid: boolean
  /** Whether the flow can be submitted */
  canSubmit: boolean
  /** Submit the flow, invoking onComplete */
  submit: () => void
  /** Cancel the flow, invoking onCancel */
  cancel: () => void
  /** Copy all words to clipboard */
  copyWords: () => Promise<void>
  /** Whether the words were recently copied */
  copied: boolean
  /** Error message for the current state */
  error: string | null
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Pick two random, distinct positions from a word list.
 * Uses Math.random which is acceptable for UI challenges (not cryptographic).
 */
function pickChallengePositions(
  wordCount: number
): [number, number] {
  const first = Math.floor(Math.random() * wordCount)
  let second = Math.floor(Math.random() * (wordCount - 1))
  if (second >= first) second += 1
  const lo = Math.min(first, second)
  const hi = Math.max(first, second)
  return [lo, hi]
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Manages all state and logic for the mnemonic seed phrase flow.
 *
 * Supports four modes:
 * - **display**: Read-only grid with copy-all button
 * - **create**: Shows generated words, requires confirmation checkbox
 * - **import**: Editable grid for entering a seed phrase
 * - **verify**: Shows 2 random word positions the user must fill in correctly
 *
 * The hook owns no UI and imports nothing from the presentation layer.
 *
 * @example
 * ```ts
 * const flow = useMnemonicFlow({
 *   mode: "create",
 *   words: generatedWords,
 *   onComplete: (words) => createWallet(words.join(" ")),
 * })
 * ```
 */
export function useMnemonicFlow({
  mode,
  words: initialWords,
  wordCount = 12,
  onComplete,
  onCancel,
}: UseMnemonicFlowOptions): UseMnemonicFlowReturn {
  const [words, setWords] = useState<string[]>(
    () => initialWords ?? Array.from<string>({ length: wordCount }).fill("")
  )
  const [confirmed, setConfirmed] = useState(false)
  const [copied, setCopied] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // Verification challenge — generated once on mount for verify mode
  const [challenge] = useState<VerificationChallenge | null>(() => {
    if (mode !== "verify") return null
    const count = initialWords?.length ?? wordCount
    return {
      positions: pickChallengePositions(count),
      answers: {},
    }
  })

  const [verificationAnswers, setVerificationAnswers] = useState<
    Record<number, string>
  >({})

  // Combine challenge with answers
  const challengeWithAnswers = useMemo<VerificationChallenge | null>(() => {
    if (!challenge) return null
    return { ...challenge, answers: verificationAnswers }
  }, [challenge, verificationAnswers])

  const setWord = useCallback(
    (index: number, value: string) => {
      setWords((prev) => {
        const next = [...prev]
        next[index] = value.trim().toLowerCase()
        return next
      })
      setError(null)
    },
    []
  )

  const setVerificationAnswer = useCallback(
    (position: number, value: string) => {
      setVerificationAnswers((prev) => ({
        ...prev,
        [position]: value.trim().toLowerCase(),
      }))
      setError(null)
    },
    []
  )

  // Validation
  const isValid = useMemo(() => {
    switch (mode) {
      case "display":
        return words.length > 0 && words.every((w) => w.length > 0)

      case "create":
        return (
          confirmed &&
          words.length > 0 &&
          words.every((w) => w.length > 0)
        )

      case "import":
        return (
          words.length === wordCount &&
          words.every((w) => w.length > 0)
        )

      case "verify": {
        if (!challenge || !initialWords) return false
        const [pos1, pos2] = challenge.positions
        return (
          verificationAnswers[pos1]?.toLowerCase() ===
            initialWords[pos1]?.toLowerCase() &&
          verificationAnswers[pos2]?.toLowerCase() ===
            initialWords[pos2]?.toLowerCase()
        )
      }

      default:
        return false
    }
  }, [mode, words, confirmed, wordCount, challenge, initialWords, verificationAnswers])

  const canSubmit = useMemo(() => {
    if (mode === "display") return false
    return isValid
  }, [mode, isValid])

  const submit = useCallback(() => {
    if (!canSubmit) return

    if (mode === "verify") {
      if (!isValid) {
        setError("Incorrect words. Please check and try again.")
        return
      }
      onComplete?.(initialWords ?? words)
      return
    }

    onComplete?.(words)
  }, [canSubmit, mode, isValid, words, initialWords, onComplete])

  const cancel = useCallback(() => {
    onCancel?.()
  }, [onCancel])

  const copyWords = useCallback(async () => {
    if (typeof navigator === "undefined") return
    try {
      await navigator.clipboard.writeText(words.join(" "))
      setCopied(true)
      setTimeout(() => setCopied(false), 2000)
    } catch {
      setError("Failed to copy to clipboard")
    }
  }, [words])

  return {
    words,
    mode,
    wordCount,
    confirmed,
    setConfirmed,
    setWord,
    setWords,
    challenge: challengeWithAnswers,
    setVerificationAnswer,
    isValid,
    canSubmit,
    submit,
    cancel,
    copyWords,
    copied,
    error,
  }
}
